module gray_counter_3bit(
    input clk,
    input rst,
    output [2:0] count
);

    reg [2:0] gray_cnt;

    always @(posedge clk) begin
        if (rst) begin
            gray_cnt <= 3'b000;
        end else begin
            gray_cnt <= gray_cnt + 1;
        end
    end

    assign count = gray_cnt ^ (gray_cnt >> 1);

endmodule
